// CLV ve RFM hesaplaması
const customers = $input.all();

const today = new Date();
const result = customers.map(({ json }) => {
  const lastOrder = new Date(json.last_order_date || json.created_at);
  const daysSinceLastOrder = Math.floor((today - lastOrder) / (1000 * 60 * 60 * 24));

  // RFM Scoring
  const recencyScore = daysSinceLastOrder <= 30 ? 5 : 
                      daysSinceLastOrder <= 60 ? 4 :
                      daysSinceLastOrder <= 90 ? 3 :
                      daysSinceLastOrder <= 180 ? 2 : 1;

  const frequencyScore = json.order_count >= 10 ? 5 :
                         json.order_count >= 5 ? 4 :
                         json.order_count >= 3 ? 3 :
                         json.order_count >= 1 ? 2 : 1;

  const monetaryScore = json.total_spent >= 50000 ? 5 :
                        json.total_spent >= 20000 ? 4 :
                        json.total_spent >= 10000 ? 3 :
                        json.total_spent >= 5000 ? 2 : 1;

  const rfmScore = recencyScore + frequencyScore + monetaryScore;

  // Segment belirleme
  let segment = 'NEW';
  if (json.order_count === 0) segment = 'POTENTIAL';
  else if (rfmScore >= 12) segment = 'CHAMPIONS';
  else if (rfmScore >= 9) segment = 'LOYAL';
  else if (daysSinceLastOrder > 60) segment = 'AT_RISK';
  else if (daysSinceLastOrder > 120) segment = 'CHURNED';
  else segment = 'ACTIVE';

  // CLV Tahmini (basit hesaplama)
  const avgOrderValue = json.order_count > 0 ? json.total_spent / json.order_count : 0;
  const expectedYearlyOrders = json.order_count > 0 ? (365 / (today - new Date(json.created_at)) * 1000 * json.order_count / 1000) : 0;
  const estimatedCLV = avgOrderValue * expectedYearlyOrders * 0.3; // 0.3 = marj

  return {
    json: {
      customerId: json.id,
      email: json.email,
      orderCount: json.order_count,
      totalSpent: json.total_spent,
      daysSinceLastOrder,
      rfmScore,
      recencyScore,
      frequencyScore,
      monetaryScore,
      segment,
      estimatedCLV: Math.round(estimatedCLV)
    }
  };
});

return result;

